7	-- https://github.com/hdl-modules/hdl-modules
8	-- -------------------------------------------------------------------------------------------------
9	-- Simple N-to-1 crossbar for connecting multiple AXI read masters to one port.
10	--
11	-- It is simple in the sense that there is no separation of AXI ``AR`` and ``R`` channels
12	-- with separate queues.
13	-- After a port has been selected for address transaction, the crossbar is
14	-- locked on that port until it has finished it's read response transactions.
15	-- After that, the crossbar moves on to do a new address transaction on, possibly,
16	-- another port.
17	--
18	-- Due to this it has a very small logic footprint but will never reach full
19	-- utilization of the data channels. In order to get higher throughput, further address transactions
20	-- should be queued up to the slave while a read response burst is running.
21	--
22	-- Arbitration is done in simplest most resource-efficient manner possible, which
23	-- means that one input port can block others if it continuously sends transactions.
24	-- -------------------------------------------------------------------------------------------------
25	
26	library ieee;
27	use ieee.std_logic_1164.all;
28	
29	library axi;
30	use axi.axi_pkg.all;
31	
32	library common;
33	use common.types_pkg.all;
34	
35	
36	entity axi_simple_read_crossbar is
37	  generic(
38	    num_inputs : positive
39	  );
40	  port(
41	    clk : in std_ulogic;
42	    --# {{}}
43	    input_ports_m2s : in axi_read_m2s_vec_t(0 to num_inputs - 1);
44	    input_ports_s2m : out axi_read_s2m_vec_t(0 to num_inputs - 1) := (others => axi_read_s2m_init);
45	    --# {{}}
46	    output_m2s : out axi_read_m2s_t := axi_read_m2s_init;
47	    output_s2m : in axi_read_s2m_t
48	  );
49	end entity;
50	
51	architecture a of axi_simple_read_crossbar is
52	
53	  signal input_select : natural range input_ports_m2s'range := 0;
54	
55	  type state_t is (idle, wait_for_ar_done, wait_for_r_done);
56	  signal state : state_t := idle;
57	
58	  signal let_ar_through, let_r_through : std_ulogic := '0';
59	
60	begin
61	
62	  ----------------------------------------------------------------------------
63	  select_input : process
64	  begin
65	    wait until rising_edge(clk);
66	
67	    case state is
68	      when idle =>
69	        for input_select_next in input_ports_m2s'range loop
70	          if input_ports_m2s(input_select_next).ar.valid then
71	            input_select <= input_select_next;
72	            state <= wait_for_ar_done;
73	          end if;
74	        end loop;
75	
76	      when wait_for_ar_done =>
77	        -- We know that 'valid' is high, otherwise we would not have gone to this state, so we
78	        -- don't have to include it in the condition.
79	        if output_s2m.ar.ready then
80	          state <= wait_for_r_done;
81	        end if;
82	
83	      when wait_for_r_done =>
84	        if output_m2s.r.ready and output_s2m.r.valid and output_s2m.r.last then
85	          state <= idle;
86	        end if;
87	
88	    end case;
89	  end process;
90	
91	  -- If these were registers set in the process above instead, it would save a little bit of
92	  -- logical depth in the combinatorial assignment below.
93	  -- Since it would be one LUT input rather than two.
94	  let_ar_through <= to_sl(state = wait_for_ar_done);
95	  let_r_through <= to_sl(state = wait_for_r_done);
96	
97	
98	  ----------------------------------------------------------------------------
99	  assign_bus : process(all)
100	  begin
101	    for input_idx in input_ports_m2s'range loop
102	      -- Default assignment of all members.
103	      input_ports_s2m(input_idx) <= output_s2m;
104	
105	      input_ports_s2m(input_idx).ar.ready <= (
106	        output_s2m.ar.ready and to_sl(input_select = input_idx) and let_ar_through
107	      );
108	      input_ports_s2m(input_idx).r.valid <= (
109	        output_s2m.r.valid and to_sl(input_select = input_idx) and let_r_through
110	      );
111	    end loop;
112	
113	    output_m2s <= input_ports_m2s(input_select);
114	
115	    output_m2s.ar.valid <= input_ports_m2s(input_select).ar.valid and let_ar_through;
116	    output_m2s.r.ready <= input_ports_m2s(input_select).r.ready and let_r_through;
117	  end process;
118	
119	end architecture;
