1	-- -------------------------------------------------------------------------------------------------
2	-- Copyright (c) Lukas Vik. All rights reserved.
3	--
4	-- This file is part of the hdl-modules project, a collection of reusable, high-quality,
5	-- peer-reviewed VHDL building blocks.
6	-- https://hdl-modules.com
7	-- https://github.com/hdl-modules/hdl-modules
8	-- -------------------------------------------------------------------------------------------------
9	-- Data types for working with AXI4 interfaces
10	--
11	-- Based on the document "ARM IHI 0022E (ID022613): AMBA AXI and ACE Protocol Specification",
12	-- available here: http://infocenter.arm.com/help/index.jsp?topic=/com.arm.doc.ihi0022e/index.html
13	-- -------------------------------------------------------------------------------------------------
14	
15	library ieee;
16	use ieee.std_logic_1164.all;
17	use ieee.numeric_std.all;
18	
19	library math;
20	use math.math_pkg.all;
21	
22	
23	package axi_pkg is
24	
25	  -- Data field (RDATA or WDATA).
26	  -- The width value below is a max value, implementation should only take into regard the bits
27	  -- that are actually used.
28	  constant axi_data_sz : positive := 128;
29	  subtype axi_data_width_t is positive range 8 to axi_data_sz;
30	
31	  ------------------------------------------------------------------------------
32	  -- A (Address Read and Address Write) channels
33	  ------------------------------------------------------------------------------
34	
35	  -- ID field (ARID, AWID, BID as well as RID if using AXI3)
36	  -- The width value below is a max value, implementation should only take into regard the bits
37	  -- that are actually used.
38	  constant axi_id_sz : positive := 24;
39	  subtype axi_id_width_t is natural range 0 to axi_id_sz;
40	
41	  -- Address field (ARADDR or AWADDR).
42	  -- The width value below is a max value, implementation should only take into regard the bits
43	  -- that are actually used.
44	  constant axi_a_addr_sz : positive := 64;
45	  subtype axi_address_width_t is positive range 1 to axi_a_addr_sz;
46	
47	  -- Length field (ARLEN or AWLEN)
48	  -- Number of beats (data transfers) in this burst = AxLEN + 1
49	  constant axi_a_len_sz : positive := 8;
50	  subtype axi_a_len_t is u_unsigned(axi_a_len_sz - 1 downto 0);
51	
52	  constant axi_max_burst_length_beats : positive := 256;
53	  constant axi3_max_burst_length_beats : positive := 16;
54	
55	  function get_max_burst_length_beats(enable_axi3 : boolean) return positive;
56	
57	  -- Find the number of AxLEN bits that have to be taken into account, given the provided
58	  -- max burst length.
59	  function get_a_len_width(
60	    max_burst_length_beats : positive range 1 to axi_max_burst_length_beats
61	  ) return positive;
62	
63	  -- Convert a given burst length to the corresponding AxLEN value.
64	  function to_len(
65	    burst_length_beats : positive range 1 to axi_max_burst_length_beats
66	  ) return axi_a_len_t;
67	
68	  -- Size field (ARSIZE or AWSIZE)
69	  -- Bytes per beat (data transfer) in this burst = 2^AxSIZE
70	  constant axi_a_size_sz : positive := 3;
71	  subtype axi_a_size_t is u_unsigned(axi_a_size_sz - 1 downto 0);
72	
73	  function to_size(data_width_bits : axi_data_width_t) return axi_a_size_t;
74	
75	  -- Burst field (ARBURST or AWBURST)
76	  constant axi_a_burst_sz : positive := 2;
77	  subtype axi_a_burst_t is std_ulogic_vector(axi_a_burst_sz - 1 downto 0);
78	
79	  constant axi_a_burst_fixed : axi_a_burst_t := "00";
80	  constant axi_a_burst_incr : axi_a_burst_t := "01";
81	  constant axi_a_burst_wrap : axi_a_burst_t := "10";
82	
83	  -- Lock field (ARLOCK or AWLOCK)
84	  -- Note that this is two bits in AXI3. We use AXI4 as the default.
85	  constant axi_a_lock_sz : positive := 1;
86	  subtype axi_a_lock_t is std_ulogic_vector(axi_a_lock_sz - 1 downto 0);
87	
88	  constant axi_a_lock_normal : axi_a_lock_t := "0";
89	  constant axi_a_lock_exclusive : axi_a_lock_t := "1";
90	
91	  subtype axi3_a_lock_t is std_ulogic_vector(2 - 1 downto 0);
92	  constant axi3_a_lock_normal : axi3_a_lock_t := "00";
93	  constant axi3_a_lock_exclusive : axi3_a_lock_t := "01";
94	  constant axi3_a_lock_locked : axi3_a_lock_t := "10";
95	
96	  -- Cache field (ARCACHE or AWCACHE)
97	  constant axi_a_cache_sz : positive := 4;
98	  subtype axi_a_cache_t is std_ulogic_vector(axi_a_cache_sz - 1 downto 0);
99	
100	  constant axi_a_cache_device_non_bufferable : axi_a_cache_t := "0000";
101	  constant axi_a_cache_device_bufferable : axi_a_cache_t := "0001";
102	  constant axi_a_cache_normal_non_cacheable_non_bufferable : axi_a_cache_t := "0010";
103	  constant axi_a_cache_normal_non_cacheable_bufferable : axi_a_cache_t := "0011";
104	  constant axi_ar_cache_write_through_no_allocate : axi_a_cache_t := "1010";
105	  constant axi_aw_cache_write_through_no_allocate : axi_a_cache_t := "0110";
106	  constant axi_a_cache_write_through_read_allocate : axi_a_cache_t := "0110";
107	  constant axi_a_cache_write_through_write_allocate : axi_a_cache_t := "1010";
108	  constant axi_a_cache_write_through_read_and_write_allocate : axi_a_cache_t := "1110";
109	  constant axi_ar_cache_write_back_no_allocate : axi_a_cache_t := "1011";
110	  constant axi_aw_cache_write_back_no_allocate : axi_a_cache_t := "0111";
111	  constant axi_a_cache_write_back_read_allocate : axi_a_cache_t := "0111";
112	  constant axi_a_cache_write_back_write_allocate : axi_a_cache_t := "1011";
113	  constant axi_a_cache_write_back_read_and_write_allocate : axi_a_cache_t := "1111";
114	
115	  -- Protocol field (ARPROT or AWPROT)
116	  constant axi_a_prot_sz : positive := 3;
117	  subtype axi_a_prot_t is std_ulogic_vector(axi_a_prot_sz - 1 downto 0);
118	
119	  constant axi_a_prot_privileged : axi_a_prot_t := "001";
120	  constant axi_a_prot_unprivileged : axi_a_prot_t := "000";
121	  constant axi_a_prot_secure : axi_a_prot_t := "000";
122	  constant axi_a_prot_nonsecure : axi_a_prot_t := "010";
123	  constant axi_a_prot_data : axi_a_prot_t := "000";
124	  constant axi_a_prot_instruction : axi_a_prot_t := "100";
125	
126	  -- Region field (ARREGION or AWREGION)
127	  constant axi_a_region_sz : positive := 4;
128	  subtype axi_a_region_t is std_ulogic_vector(axi_a_region_sz - 1 downto 0);
129	
130	  -- Record for the AR/AW signals in the master-to-slave direction.
131	  type axi_m2s_a_t is record
132	    valid : std_ulogic;
133	    id : u_unsigned(axi_id_sz - 1 downto 0);
134	    addr : u_unsigned(axi_a_addr_sz - 1 downto 0);
135	    len : axi_a_len_t;
136	    size : axi_a_size_t;
137	    burst : axi_a_burst_t;
138	    -- Excluded members: lock, cache, prot, region.
139	    -- These are typically not changed on a transfer-to-transfer basis.
140	  end record;
141	
142	  constant axi_m2s_a_init : axi_m2s_a_t := (
143	    valid => '0',
144	    id => (others => '0'),
145	    addr => (others => '0'),
146	    len => (others => '-'),
147	    size => (others => '-'),
148	    burst => (others => '-')
149	  );
150	  function axi_m2s_a_sz(
151	    id_width : axi_id_width_t; addr_width : axi_address_width_t
152	  ) return positive;
153	  type axi_m2s_a_vec_t is array (integer range <>) of axi_m2s_a_t;
154	
155	  function to_slv(
156	    data : axi_m2s_a_t;
157	    id_width : axi_id_width_t;
158	    addr_width : axi_address_width_t
159	  ) return std_ulogic_vector;
160	  function to_axi_m2s_a(
161	    data : std_ulogic_vector;
162	    id_width : axi_id_width_t;
163	    addr_width : axi_address_width_t
164	  ) return axi_m2s_a_t;
165	
166	  -- Record for the AR/AW signals in the slave-to-master direction.
167	  type axi_s2m_a_t is record
168	    ready : std_ulogic;
169	  end record;
170	
171	  constant axi_s2m_a_init : axi_s2m_a_t := (ready => '0');
172	  type axi_s2m_a_vec_t is array (integer range <>) of axi_s2m_a_t;
173	
174	
175	  ------------------------------------------------------------------------------
176	  -- W (Write Data) channels
177	  ------------------------------------------------------------------------------
178	
179	  -- Check that a provided data width is valid to be used with AXI.
180	  -- Return 'true' if everything is okay, otherwise 'false'.
181	  function sanity_check_axi_data_width(data_width : integer) return boolean;
182	
183	  -- Write data strobe field (WSTRB).
184	  -- The width value below is a max value, implementation should only take into regard the bits
185	  -- that are actually used.
186	  constant axi_w_strb_sz : positive := axi_data_sz / 8;
187	
188	  function to_strb(data_width : axi_data_width_t) return std_ulogic_vector;
189	  function axi_w_strb_width(data_width : axi_data_width_t) return positive;
190	
191	  -- Record for the W signals in the master-to-slave direction.
192	  type axi_m2s_w_t is record
193	    valid : std_ulogic;
194	    data : std_ulogic_vector(axi_data_sz - 1 downto 0);
195	    strb : std_ulogic_vector(axi_w_strb_sz - 1 downto 0);
196	    last : std_ulogic;
197	    -- Only available in AXI3. We assume that AXI4 is used most of the time, hence id_width is
198	    -- defaulted to zero in the functions below.
199	    id : u_unsigned(axi_id_sz - 1 downto 0);
200	  end record;
201	
202	  constant axi_m2s_w_init : axi_m2s_w_t := (
203	    valid => '0',
204	    data => (others => '-'),
205	    strb => (others => '0'),
206	    last => '-',
207	    id => (others => '-')
208	  );
209	  function axi_m2s_w_sz(
210	    data_width : axi_data_width_t; id_width : axi_id_width_t := 0
211	  ) return positive;
212	  type axi_m2s_w_vec_t is array (integer range <>) of axi_m2s_w_t;
213	
214	  function to_slv(
215	    data : axi_m2s_w_t;
216	    data_width : axi_data_width_t;
217	    id_width : axi_id_width_t := 0
218	  ) return std_ulogic_vector;
219	  function to_axi_m2s_w(
220	    data : std_ulogic_vector;
221	    data_width : axi_data_width_t;
222	    id_width : axi_id_width_t := 0
223	  ) return axi_m2s_w_t;
224	
225	  -- Record for the W signals in the slave-to-master direction.
226	  type axi_s2m_w_t is record
227	    ready : std_ulogic;
228	  end record;
229	  type axi_s2m_w_vec_t is array (integer range <>) of axi_s2m_w_t;
230	
231	  constant axi_s2m_w_init : axi_s2m_w_t := (ready => '0');
232	
233	
234	  ------------------------------------------------------------------------------
235	  -- B (Write Response) channels
236	  ------------------------------------------------------------------------------
237	
238	  -- Record for the W signals in the master-to-slave direction.
239	  type axi_m2s_b_t is record
240	    ready : std_ulogic;
241	  end record;
242	
243	  constant axi_m2s_b_init : axi_m2s_b_t := (ready => '0');
244	
245	  -- Response field (RRESP or BRESP).
246	  constant axi_resp_sz : positive := 2;
247	  subtype axi_resp_t is std_ulogic_vector(axi_resp_sz - 1 downto 0);
248	
249	  -- Okay.
250	  constant axi_resp_okay : axi_resp_t := "00";
251	  -- Exclusive access okay.
252	  constant axi_resp_exokay : axi_resp_t := "01";
253	  -- Slave error. Slave wishes to return error.
254	  constant axi_resp_slverr : axi_resp_t := "10";
255	  -- Decode error. There is no slave at transaction address.
256	  constant axi_resp_decerr : axi_resp_t := "11";
257	
258	  -- Record for the B signals in the slave-to-master direction.
259	  type axi_s2m_b_t is record
260	    valid : std_ulogic;
261	    id : u_unsigned(axi_id_sz - 1 downto 0);
262	    resp : axi_resp_t;
263	  end record;
264	
265	  constant axi_s2m_b_init : axi_s2m_b_t := (
266	    valid => '0',
267	    id => (others => '0'),
268	    resp => (others => '-')
269	  );
270	  function axi_s2m_b_sz(id_width : axi_id_width_t) return positive;
271	  type axi_s2m_b_vec_t is array (integer range <>) of axi_s2m_b_t;
272	
273	  function to_slv(
274	    data : axi_s2m_b_t; id_width : axi_id_width_t
275	  ) return std_ulogic_vector;
276	  function to_axi_s2m_b(
277	    data : std_ulogic_vector; id_width : axi_id_width_t
278	  ) return axi_s2m_b_t;
279	
280	
281	  ------------------------------------------------------------------------------
282	  -- R (Read Data) channels
283	  ------------------------------------------------------------------------------
284	
285	  -- Record for the R signals in the master-to-slave direction.
286	  type axi_m2s_r_t is record
287	    ready : std_ulogic;
288	  end record;
289	  type axi_m2s_r_vec_t is array (integer range <>) of axi_m2s_r_t;
290	
291	  constant axi_m2s_r_init : axi_m2s_r_t := (ready => '0');
292	
293	  -- Record for the R signals in the slave-to-master direction.
294	  type axi_s2m_r_t is record
295	    valid : std_ulogic;
296	    id : u_unsigned(axi_id_sz - 1 downto 0);
297	    data : std_ulogic_vector(axi_data_sz - 1 downto 0);
298	    resp : axi_resp_t;
299	    last : std_ulogic;
300	  end record;
301	
302	  constant axi_s2m_r_init : axi_s2m_r_t := (
303	    valid => '0',
304	    id => (others => '0'),
305	    data => (others => '-'),
306	    resp => (others => '-'),
307	    last => '-'
308	  );
309	  function axi_s2m_r_sz(
310	    data_width : axi_data_width_t; id_width : axi_id_width_t
311	  )  return positive;
312	  type axi_s2m_r_vec_t is array (integer range <>) of axi_s2m_r_t;
313	
314	  function to_slv(
315	    data : axi_s2m_r_t;
316	    data_width : axi_data_width_t;
317	    id_width : axi_id_width_t
318	  ) return std_ulogic_vector;
319	  function to_axi_s2m_r(
320	    data : std_ulogic_vector;
321	    data_width : axi_data_width_t;
322	    id_width : axi_id_width_t
323	  ) return axi_s2m_r_t;
324	
325	
326	  ------------------------------------------------------------------------------
327	  -- The complete buses
328	  ------------------------------------------------------------------------------
329	
330	  type axi_read_m2s_t is record
331	    ar : axi_m2s_a_t;
332	    r : axi_m2s_r_t;
333	  end record;
334	  type axi_read_m2s_vec_t is array (integer range <>) of axi_read_m2s_t;
335	
336	  constant axi_read_m2s_init : axi_read_m2s_t := (ar => axi_m2s_a_init, r => axi_m2s_r_init);
337	
338	  type axi_read_s2m_t is record
339	    ar : axi_s2m_a_t;
340	    r : axi_s2m_r_t;
341	  end record;
342	  type axi_read_s2m_vec_t is array (integer range <>) of axi_read_s2m_t;
343	
344	  constant axi_read_s2m_init : axi_read_s2m_t := (ar => axi_s2m_a_init, r => axi_s2m_r_init);
345	
346	  type axi_write_m2s_t is record
347	    aw : axi_m2s_a_t;
348	    w : axi_m2s_w_t;
349	    b : axi_m2s_b_t;
350	  end record;
351	  type axi_write_m2s_vec_t is array (integer range <>) of axi_write_m2s_t;
352	
353	  constant axi_write_m2s_init : axi_write_m2s_t := (
354	    aw => axi_m2s_a_init,
355	    w => axi_m2s_w_init,
356	    b => axi_m2s_b_init
357	  );
358	
359	  type axi_write_s2m_t is record
360	    aw : axi_s2m_a_t;
361	    w : axi_s2m_w_t;
362	    b : axi_s2m_b_t;
363	  end record;
364	  type axi_write_s2m_vec_t is array (integer range <>) of axi_write_s2m_t;
365	
366	  constant axi_write_s2m_init : axi_write_s2m_t := (
367	    aw => axi_s2m_a_init,
368	    w => axi_s2m_w_init,
369	    b => axi_s2m_b_init
370	  );
371	
372	  type axi_m2s_t is record
373	    read : axi_read_m2s_t;
374	    write : axi_write_m2s_t;
375	  end record;
376	  type axi_m2s_vec_t is array (integer range <>) of axi_m2s_t;
377	
378	  constant axi_m2s_init : axi_m2s_t := (read => axi_read_m2s_init, write => axi_write_m2s_init);
379	
380	  type axi_s2m_t is record
381	    read : axi_read_s2m_t;
382	    write : axi_write_s2m_t;
383	  end record;
384	  type axi_s2m_vec_t is array (integer range <>) of axi_s2m_t;
385	
386	  constant axi_s2m_init : axi_s2m_t := (read => axi_read_s2m_init, write => axi_write_s2m_init);
387	
388	  function combine_response(resp1, resp2 : axi_resp_t) return axi_resp_t;
389	
390	end;
391	
392	package body axi_pkg is
393	
394	  ------------------------------------------------------------------------------
395	  function get_max_burst_length_beats(enable_axi3 : boolean) return positive is
396	  begin
397	    if enable_axi3 then
398	      return axi3_max_burst_length_beats;
399	    end if;
400	
401	    return axi_max_burst_length_beats;
402	  end function;
403	
404	  function get_a_len_width(
405	    max_burst_length_beats : positive range 1 to axi_max_burst_length_beats
406	  ) return positive is
407	    constant max_a_len : positive := max_burst_length_beats - 1;
408	    constant result : positive range 1 to axi_a_len_sz := num_bits_needed(max_a_len);
409	  begin
410	    assert (
411	        max_burst_length_beats = axi_max_burst_length_beats
412	        or max_burst_length_beats = axi3_max_burst_length_beats
413	      )
414	      report "Invalid max burst length"
415	      severity failure;
416	
417	    return result;
418	  end function;
419	
420	  function to_len(
421	    burst_length_beats : positive range 1 to axi_max_burst_length_beats
422	  ) return axi_a_len_t is
423	    -- burst_length_beats is number of transfers
424	    constant result : axi_a_len_t := to_unsigned(burst_length_beats - 1, axi_a_len_sz);
425	  begin
426	    return result;
427	  end function;
428	
429	  function to_size(data_width_bits : axi_data_width_t) return axi_a_size_t is
430	    constant result : axi_a_size_t := to_unsigned(log2(data_width_bits / 8), axi_a_size_sz);
431	  begin
432	    assert sanity_check_axi_data_width(data_width_bits)
433	      report "Invalid data width, see printout above."
434	      severity failure;
435	
436	    return result;
437	  end function;
438	
439	  function axi_m2s_a_sz(
440	    id_width : axi_id_width_t; addr_width : axi_address_width_t
441	  ) return positive is
442	  begin
443	    -- Excluded member: valid
444	    return id_width + addr_width + axi_a_len_sz + axi_a_size_sz + axi_a_burst_sz;
445	  end function;
446	
447	  function to_slv(
448	    data : axi_m2s_a_t;
449	    id_width : axi_id_width_t;
450	    addr_width : axi_address_width_t
451	  ) return std_ulogic_vector is
452	    variable result : std_ulogic_vector(axi_m2s_a_sz(id_width, addr_width) - 1 downto 0);
453	    variable lo, hi : natural := 0;
454	  begin
455	    lo := 0;
456	    if id_width > 0 then
457	      hi := id_width - 1;
458	      result(hi downto lo) := std_ulogic_vector(data.id(hi downto lo));
459	
460	      lo := hi + 1;
461	    end if;
462	    hi := lo + addr_width - 1;
463	    result(hi downto lo) := std_ulogic_vector(data.addr(addr_width - 1 downto 0));
464	
465	    lo := hi + 1;
466	    hi := lo + data.len'length - 1;
467	    result(hi downto lo) := std_ulogic_vector(data.len);
468	
469	    lo := hi + 1;
470	    hi := lo + data.size'length - 1;
471	    result(hi downto lo) := std_ulogic_vector(data.size);
472	
473	    lo := hi + 1;
474	    hi := lo + data.burst'length - 1;
475	    result(hi downto lo) := data.burst;
476	
477	    assert hi = result'high;
478	
479	    return result;
480	  end function;
481	
482	  function to_axi_m2s_a(
483	    data : std_ulogic_vector;
484	    id_width : axi_id_width_t;
485	    addr_width : axi_address_width_t
486	  ) return axi_m2s_a_t is
487	    constant offset : natural := data'low;
488	    variable result : axi_m2s_a_t := axi_m2s_a_init;
489	    variable lo, hi : natural := 0;
490	  begin
491	    lo := 0;
492	    if id_width > 0 then
493	      hi := id_width - 1;
494	      result.id(hi downto lo) := u_unsigned(data(hi + offset downto lo + offset));
495	
496	      lo := hi + 1;
497	    end if;
498	    hi := lo + addr_width - 1;
499	    result.addr(addr_width - 1 downto 0) := u_unsigned(data(hi + offset downto lo + offset));
500	
501	    lo := hi + 1;
502	    hi := lo + result.len'length - 1;
503	    result.len := u_unsigned(data(hi + offset downto lo + offset));
504	
505	    lo := hi + 1;
506	    hi := lo + result.size'length - 1;
507	    result.size := u_unsigned(data(hi + offset downto lo + offset));
508	
509	    lo := hi + 1;
510	    hi := lo + result.burst'length - 1;
511	    result.burst := data(hi + offset downto lo + offset);
512	
513	    assert hi + offset = data'high;
514	
515	    return result;
516	  end function;
517	  ------------------------------------------------------------------------------
518	
519	  ------------------------------------------------------------------------------
520	  function sanity_check_axi_data_width(data_width : integer) return boolean is
521	    constant message : string := ". Got data_width=" & integer'image(data_width) & ".";
522	  begin
523	    if data_width <= 0 then
524	      report "AXI data width must be greater than zero" & message;
525	      return false;
526	    end if;
527	
528	    if data_width > axi_data_sz then
529	      report (
530	        "AXI data width must not be greater than max value "
531	        & integer'image(axi_data_sz)
532	        & message
533	      );
534	      return false;
535	    end if;
536	
537	    if data_width mod 8 /= 0 then
538	      report "AXI data width must be a whole number of bytes" & message;
539	      return false;
540	    end if;
541	
542	    if not is_power_of_two(data_width / 8) then
543	      report "AXI data byte width must be a power of two" & message;
544	      return false;
545	    end if;
546	
547	    return true;
548	  end function;
549	
550	  function to_strb(data_width : axi_data_width_t) return std_ulogic_vector is
551	    variable result : std_ulogic_vector(axi_w_strb_sz - 1 downto 0) := (others => '0');
552	  begin
553	    assert sanity_check_axi_data_width(data_width)
554	      report "Invalid data width, see printout above."
555	      severity failure;
556	
557	    result(data_width / 8 - 1 downto 0) := (others => '1');
558	
559	    return result;
560	  end function;
561	
562	  function axi_w_strb_width(data_width : axi_data_width_t) return positive is
563	  begin
564	    assert sanity_check_axi_data_width(data_width)
565	      report "Invalid data width, see printout above."
566	      severity failure;
567	
568	    return data_width / 8;
569	  end function;
570	
571	  function axi_m2s_w_sz(
572	    data_width : axi_data_width_t; id_width : axi_id_width_t := 0
573	  ) return positive is
574	  begin
575	    assert sanity_check_axi_data_width(data_width)
576	      report "Invalid data width, see printout above."
577	      severity failure;
578	
579	    -- Excluded member: valid.
580	    -- The 1 is for 'last'.
581	    return data_width + axi_w_strb_width(data_width) + 1 + id_width;
582	  end function;
583	
584	  function to_slv(
585	    data : axi_m2s_w_t;
586	    data_width : axi_data_width_t;
587	    id_width : axi_id_width_t := 0
588	  ) return std_ulogic_vector is
589	    constant result_width : positive := axi_m2s_w_sz(data_width=>data_width, id_width=>id_width);
590	    variable result : std_ulogic_vector(result_width - 1 downto 0) := (others => '0');
591	    variable lo, hi : natural := 0;
592	  begin
593	    lo := 0;
594	    hi := lo + data_width - 1;
595	    result(hi downto lo) := data.data(data_width - 1 downto 0);
596	
597	    lo := hi + 1;
598	    hi := lo + axi_w_strb_width(data_width) - 1;
599	    result(hi downto lo) := data.strb(axi_w_strb_width(data_width) - 1 downto 0);
600	
601	    lo := hi + 1;
602	    hi := lo + id_width - 1;
603	    result(hi downto lo) := std_ulogic_vector(data.id(id_width - 1 downto 0));
604	
605	    lo := hi + 1;
606	    hi := lo;
607	    result(hi) := data.last;
608	
609	    assert hi = result'high;
610	
611	    return result;
612	  end function;
613	
614	  function to_axi_m2s_w(
615	    data : std_ulogic_vector;
616	    data_width : axi_data_width_t;
617	    id_width : axi_id_width_t := 0
618	  ) return axi_m2s_w_t is
619	    constant offset : natural := data'low;
620	    variable result : axi_m2s_w_t := axi_m2s_w_init;
621	    variable lo, hi : natural := 0;
622	  begin
623	    lo := 0;
624	    hi := lo + data_width - 1;
625	    result.data(data_width - 1 downto 0) := data(hi + offset downto lo + offset);
626	
627	    lo := hi + 1;
628	    hi := lo + axi_w_strb_width(data_width) - 1;
629	    result.strb(axi_w_strb_width(data_width) - 1 downto 0) := data(hi + offset downto lo + offset);
630	
631	    lo := hi + 1;
632	    hi := lo + id_width - 1;
633	    result.id(id_width - 1 downto 0) := u_unsigned(data(hi + offset downto lo + offset));
634	
635	    lo := hi + 1;
636	    hi := lo;
637	    result.last := data(hi + offset);
638	
639	    assert hi + offset = data'high;
640	
641	    return result;
642	  end function;
643	  ------------------------------------------------------------------------------
644	
645	  ------------------------------------------------------------------------------
646	  function axi_s2m_b_sz(id_width : axi_id_width_t) return positive is
647	  begin
648	    -- Excluded member: valid
649	    return id_width + axi_resp_sz;
650	  end function;
651	
652	  function to_slv(
653	    data : axi_s2m_b_t; id_width : axi_id_width_t
654	  ) return std_ulogic_vector is
655	    variable result : std_ulogic_vector(axi_s2m_b_sz(id_width) - 1 downto 0);
656	    variable lo, hi : natural := 0;
657	  begin
658	    lo := 0;
659	    if id_width > 0 then
660	      hi := id_width - 1;
661	      result(hi downto lo) := std_ulogic_vector(data.id(hi downto lo));
662	
663	      lo := hi + 1;
664	    end if;
665	    hi := lo + axi_resp_sz - 1;
666	    result(hi downto lo) := data.resp;
667	
668	    assert hi = result'high;
669	
670	    return result;
671	  end function;
672	
673	  function to_axi_s2m_b(
674	    data : std_ulogic_vector; id_width : axi_id_width_t
675	  ) return axi_s2m_b_t is
676	    constant offset : natural := data'low;
677	    variable result : axi_s2m_b_t := axi_s2m_b_init;
678	    variable lo, hi : natural := 0;
679	  begin
680	    lo := 0;
681	    if id_width > 0 then
682	      hi := id_width - 1;
683	      result.id(hi downto lo) := u_unsigned(data(hi + offset downto lo + offset));
684	
685	      lo := hi + 1;
686	    end if;
687	    hi := lo + axi_resp_sz - 1;
688	    result.resp := data(hi + offset downto lo + offset);
689	
690	    assert hi + offset = data'high;
691	
692	    return result;
693	  end function;
694	  ------------------------------------------------------------------------------
695	
696	  ------------------------------------------------------------------------------
697	  function axi_s2m_r_sz(
698	    data_width : axi_data_width_t; id_width : axi_id_width_t
699	  ) return positive is
700	  begin
701	    assert sanity_check_axi_data_width(data_width)
702	      report "Invalid data width, see printout above."
703	      severity failure;
704	
705	    -- Excluded member: valid.
706	    -- The 1 is for 'last'.
707	    return data_width + id_width + axi_resp_sz + 1;
708	  end function;
709	
710	  function to_slv(
711	    data : axi_s2m_r_t;
712	    data_width : axi_data_width_t;
713	    id_width : axi_id_width_t)
714	  return std_ulogic_vector is
715	    variable result : std_ulogic_vector(axi_s2m_r_sz(data_width, id_width) - 1 downto 0);
716	    variable lo, hi : natural := 0;
717	  begin
718	    lo := 0;
719	    if id_width > 0 then
720	      hi := id_width - 1;
721	      result(hi downto lo) := std_ulogic_vector(data.id(hi downto lo));
722	
723	      lo := hi + 1;
724	    end if;
725	    hi := lo + data_width - 1;
726	    result(hi downto lo) := data.data(data_width - 1 downto 0);
727	
728	    lo := hi + 1;
729	    hi := lo + axi_resp_sz - 1;
730	    result(hi downto lo) := data.resp;
731	
732	    lo := hi + 1;
733	    hi := lo;
734	    result(hi) := data.last;
735	
736	    assert hi = result'high;
737	
738	    return result;
739	  end function;
740	
741	  function to_axi_s2m_r(
742	    data : std_ulogic_vector;
743	    data_width : axi_data_width_t;
744	    id_width : axi_id_width_t
745	  ) return axi_s2m_r_t is
746	    constant offset : natural := data'low;
747	    variable result : axi_s2m_r_t := axi_s2m_r_init;
748	    variable lo, hi : natural := 0;
749	  begin
750	    lo := 0;
751	    if id_width > 0 then
752	      hi := id_width - 1;
753	      result.id(hi downto lo) := u_unsigned(data(hi + offset downto lo + offset));
754	
755	      lo := hi + 1;
756	    end if;
757	    hi := lo + data_width - 1;
758	    result.data(data_width - 1 downto 0) := data(hi + offset downto lo + offset);
759	
760	    lo := hi + 1;
761	    hi := lo + axi_resp_sz - 1;
762	    result.resp := data(hi + offset downto lo + offset);
763	
764	    lo := hi + 1;
765	    hi := lo;
766	    result.last := data(hi + offset);
767	
768	    assert hi + offset = data'high;
769	
770	    return result;
771	  end function;
772	  ------------------------------------------------------------------------------
773	
774	  ------------------------------------------------------------------------------
775	  -- Combine responses, with the "worst" response taking priority. OKAY may be considered
776	  -- an error if an exclusive access was desired, so OKAY takes priority over EXOKAY.
777	  function combine_response(resp1, resp2 : axi_resp_t) return axi_resp_t is
778	    variable resp : axi_resp_t;
779	  begin
780	    resp := resp1;
781	
782	    case resp is
783	      when axi_resp_exokay =>
784	        -- All values take priority over EXOKAY
785	        resp := resp2;
786	
787	      when axi_resp_okay =>
788	        -- Errors take priority over OKAY
789	        if resp2 = axi_resp_slverr then
790	          resp := axi_resp_slverr;
791	        end if;
792	        if resp2 = axi_resp_decerr then
793	          resp := axi_resp_decerr;
794	        end if;
795	
796	      when axi_resp_slverr =>
797	        -- Only DECERR takes priority over SLVERR
798	        if resp2 = axi_resp_decerr then
799	          resp := axi_resp_decerr;
800	        end if;
801	
802	      when others =>
803	        -- DECERR
804	        resp := axi_resp_decerr;
805	
806	    end case;
807	
808	    return resp;
809	  end function;
810	  ------------------------------------------------------------------------------
811	
812	end;
