57	
58	  type state_t is (idle, wait_for_aw_done, wait_for_w_done, wait_for_b_done);
59	  signal state : state_t := idle;
60	
61	  signal let_aw_through, let_w_through, let_b_through : std_ulogic := '0';
62	
63	begin
64	
65	  ----------------------------------------------------------------------------
66	  select_input : process
67	  begin
68	    wait until rising_edge(clk);
69	
70	    case state is
71	      when idle =>
72	        for input_select_next in input_ports_m2s'range loop
73	          if input_ports_m2s(input_select_next).aw.valid then
74	            input_select <= input_select_next;
75	            state <= wait_for_aw_done;
76	          end if;
77	        end loop;
78	
79	      when wait_for_aw_done =>
