81	        -- don't have to include it in the condition.
82	        if output_s2m.aw.ready then
83	          state <= wait_for_w_done;
84	        end if;
85	
86	      when wait_for_w_done =>
87	        if output_s2m.w.ready and output_m2s.w.valid and output_m2s.w.last then
88	          state <= wait_for_b_done;
89	        end if;
90	
91	      when wait_for_b_done =>
92	        if output_m2s.b.ready and output_s2m.b.valid then
93	          state <= idle;
94	        end if;
95	
