1	-- -------------------------------------------------------------------------------------------------
2	-- Copyright (c) Lukas Vik. All rights reserved.
3	--
4	-- This file is part of the hdl-modules project, a collection of reusable, high-quality,
5	-- peer-reviewed VHDL building blocks.
6	-- https://hdl-modules.com
7	-- https://github.com/hdl-modules/hdl-modules
8	-- -------------------------------------------------------------------------------------------------
9	-- Performs throttling of an AXI read bus by limiting the number of outstanding
10	-- transactions, which makes the AXI master well behaved.
11	--
12	-- This entity is to be used in conjunction with a data FIFO (:ref:`fifo.fifo`
13	-- or :ref:`fifo.asynchronous_fifo`) on the ``input.r`` side.
14	-- Using the level from that FIFO, the throttling will make sure that address
15	-- transactions are not made that would result in the FIFO becoming full. This
16	-- avoids stalling on the ``throttled_s2m.r`` channel.
17	--
18	-- .. digraph:: my_graph
19	--
20	--   graph [dpi = 300];
21	--   rankdir="LR";
22	--
23	--   ar [shape=none label="AR"];
24	--   r [shape=none label="R"];
25	--
26	--   {
27	--     rank=same;
28	--     ar;
29	--     r;
30	--   }
31	--
32	--   r_fifo [label="" shape=none image="fifo.png"];
33	--   r -> r_fifo [dir="back"];
34	--
35	--   axi_read_throttle [shape=box label="AXI read\nthrottle"];
36	--   ar:e -> axi_read_throttle;
37	--   r_fifo:e -> axi_read_throttle [dir="back"];
38	--   r_fifo:s -> axi_read_throttle:s [label="level"];
39	--
40	--   axi_slave [shape=box label="AXI slave" height=2];
41	--
42	--   axi_read_throttle -> axi_slave [dir="both" label="AXI\nread"];
43	--
44	-- To achieve this it keeps track of the number of outstanding beats
45	-- that have been negotiated but not yet sent.
46	--
47	-- .. warning::
48	--
49	--   The FIFO implementation must update the level counter on the same rising clock edge as the FIFO
50	--   write transaction, i.e. the ``input.r`` transaction.
51	--   Otherwise the throttling will not work correctly.
52	--   This condition is fulfilled by :ref:`fifo.fifo`, :ref:`fifo.asynchronous_fifo` and most other
53	--   FIFO implementations.
54	--
55	-- The imagined use case for this entity is with an AXI crossbar where the throughput should not
56	-- be limited by one port starving out the others by being ill behaved.
57	-- In this case it makes sense to use this throttler on each port.
58	--
59	-- However if a crossbar is not used, and the AXI bus goes directly to an AXI slave that has FIFOs
60	-- on the ``AR`` and ``R`` channels, then there is no point to using this throttler.
61	-- These FIFOs can be either in logic (in e.g. an AXI DDR4 controller) or in the "hard"
62	-- AXI controller in e.g. a Xilinx Zynq device.
63	-- -------------------------------------------------------------------------------------------------
64	
65	library ieee;
66	use ieee.numeric_std.all;
67	use ieee.std_logic_1164.all;
68	
69	library axi;
70	use axi.axi_pkg.all;
71	
72	library common;
73	use common.types_pkg.all;
74	
75	library math;
76	use math.math_pkg.all;
77	
78	
79	entity axi_read_throttle is
80	  generic(
81	    data_fifo_depth : positive;
82	    max_burst_length_beats : positive;
83	    id_width : axi_id_width_t;
84	    addr_width : axi_address_width_t;
85	    -- The AR channel is pipelined one step to improve poor timing, mainly on ARVALID.
86	    -- If this generic is set to false, the pipelining will be of a simpler model that has lower
87	    -- logic footprint, but only allow a transaction every third clock cycle. If it is set to true,
88	    -- the pipeline will support a transaction every clock cycle, at the cost of a greater
89	    -- logic footprint.
90	    full_ar_throughput : boolean
91	  );
92	  port(
93	    clk : in std_ulogic;
94	    --# {{}}
95	    data_fifo_level : in natural range 0 to data_fifo_depth;
96	    --# {{}}
97	    input_m2s : in axi_read_m2s_t;
98	    input_s2m : out axi_read_s2m_t := axi_read_s2m_init;
99	    --# {{}}
100	    throttled_m2s : out axi_read_m2s_t := axi_read_m2s_init;
101	    throttled_s2m : in axi_read_s2m_t
102	  );
103	end entity;
104	
105	architecture a of axi_read_throttle is
106	
107	  signal pipelined_m2s_ar : axi_m2s_a_t := axi_m2s_a_init;
108	  signal pipelined_s2m_ar : axi_s2m_a_t := axi_s2m_a_init;
109	
110	  signal address_transaction, data_transaction, data_transaction_p1 : std_ulogic := '0';
111	
112	  -- The bits of the ARLEN field that shall be taken into account
113	  constant len_width : positive := num_bits_needed(max_burst_length_beats - 1);
114	  subtype len_range is natural range len_width - 1 downto 0;
115	
116	  -- +1 in range for sign bit
117	  signal minus_burst_length_beats : u_signed(len_width + 1 - 1 downto 0) := (others => '0');
118	
119	  -- Number of data beats that have been negotiated via address transactions,
120	  -- but have not yet been sent by the master. Aka outstanding beats.
121	  -- Note that according to the AXI standard, RVALID may never arrive before ARREADY.
122	  -- Hence this counter can never go negative.
123	  subtype data_counter_t is natural range 0 to data_fifo_depth;
124	  signal num_beats_negotiated_but_not_sent : data_counter_t := 0;
125	
126	  -- Negation of:
127	  -- Number of data beat words empty in the FIFO, that are not claimed by outstanding transactions.
128	  signal minus_num_empty_words_in_fifo_that_have_not_been_negotiated :
129	    integer range -data_fifo_depth to 0 := 0;
130	
131	begin
132	
133	  ------------------------------------------------------------------------------
134	  pipeline : block
135	    constant m2s_length : positive := axi_m2s_a_sz(id_width=>id_width, addr_width=>addr_width);
136	    signal input_m2s_ar_slv, pipelined_m2s_ar_slv : std_ulogic_vector(m2s_length - 1 downto 0) := (
137	      others => '0'
138	    );
139	    signal pipelined_valid : std_ulogic := '0';
140	  begin
141	
142	    input_m2s_ar_slv <= to_slv(data=>input_m2s.ar, id_width=>id_width, addr_width=>addr_width);
143	
144	
145	    ------------------------------------------------------------------------------
146	    handshake_pipeline_inst : entity common.handshake_pipeline
147	      generic map (
148	        data_width => input_m2s_ar_slv'length,
149	        -- Choosable by user, since it affects footprint.
150	        full_throughput => full_ar_throughput,
151	        -- The goal of this pipeline is to improve timing of the control bits, so this one must
152	        -- be true, even though it will increase footprint.
153	        pipeline_control_signals => true
154	      )
155	      port map (
156	        clk => clk,
157	        --
158	        input_ready => input_s2m.ar.ready,
159	        input_valid => input_m2s.ar.valid,
160	        input_data => input_m2s_ar_slv,
161	        --
162	        output_ready => pipelined_s2m_ar.ready,
163	        output_valid => pipelined_valid,
164	        output_data => pipelined_m2s_ar_slv
165	      );
166	
167	
168	    ------------------------------------------------------------------------------
169	    assign_ar : process(all)
170	    begin
171	      pipelined_m2s_ar <= to_axi_m2s_a(
172	        data=>pipelined_m2s_ar_slv, id_width=>id_width, addr_width=>addr_width
173	      );
174	      pipelined_m2s_ar.valid <= pipelined_valid;
175	    end process;
176	
177	  end block;
178	
179	
180	  -- Two complement inversion: inv(len) = - len - 1 = - (len + 1) = - burst_length_beats
181	  minus_burst_length_beats <= not u_signed('0' & pipelined_m2s_ar.len(len_range));
182	
183	
184	  ------------------------------------------------------------------------------
185	  assign : process(all)
186	    variable block_address_transactions : boolean;
187	  begin
188	    throttled_m2s.ar <= pipelined_m2s_ar;
189	    pipelined_s2m_ar <= throttled_s2m.ar;
190	
191	    throttled_m2s.r <= input_m2s.r;
192	    input_s2m.r <= throttled_s2m.r;
193	
194	    -- The original condition would have been
195	    --
196	    -- block_address_transactions =
197	    --   burst_length_beats >= num_empty_words_in_fifo_that_have_not_been_negotiated
198	    --
199	    -- where num_empty_words_in_fifo_that_have_not_been_negotiated =
200	    --   num_empty_words_in_fifo - num_beats_negotiated_but_not_sent
201	    --
202	    -- where num_beats_negotiated_but_not_sent was given by accumulating
203	    --   to_int(address_transaction) * burst_length_beats - to_int(data_transaction)
204	    --
205	    -- However this created a very long critical path from ARLEN to ARVALID. The
206	    -- bytes_per_beat = ARLEN + 1 term, used in two places was replaced with -inv(ARLEN).
207	    -- The minus sign was moved to the right side of the expression, which changed the subtraction
208	    -- order. This makes the signals and their ranges a bit harder to understand, but it improves
209	    -- the critical path a lot.
210	    block_address_transactions :=
211	      minus_burst_length_beats <= minus_num_empty_words_in_fifo_that_have_not_been_negotiated;
212	    if block_address_transactions then
213	      throttled_m2s.ar.valid <= '0';
214	      pipelined_s2m_ar.ready <= '0';
215	    end if;
216	  end process;
217	
218	
219	  ------------------------------------------------------------------------------
220	  count : process
221	    variable num_empty_words_in_fifo, num_beats_negotiated_but_not_sent_int
222	      : data_counter_t := 0;
223	    variable ar_term : u_signed(minus_burst_length_beats'range) := (others => '0');
224	  begin
225	    wait until rising_edge(clk);
226	
227	    -- This multiplexing results in a shorter critical path than doing
228	    -- e.g. minus_burst_length_beats * to_int(address_transaction).
229	    -- LUT usage stayed the same.
230	    if address_transaction then
231	      ar_term := minus_burst_length_beats;
232	    else
233	      ar_term := (others => '0');
234	    end if;
235	
236	    -- This term is compared with 'data_fifo_level' below.
237	    -- Since 'data_fifo_level' is updated on the rising edge where 'RREADY and RVALID' is
238	    -- true, we need to delay 'data_transaction' by one clock cycle so that they match.
239	    -- Otherwise 'ARVALID' could be raised when an 'R' transaction occurs, because we think we have
240	    -- space in the FIFO, but then lowered again the next clock cycle when 'data_fifo_level'
241	    -- is updated.
242	    -- The 'AR' part of the arithmetic needs to be updated straight away however, so that we do not
243	    -- send more transactions than we have space for.
244	    -- Otherwise we could have pipelined the whole calculation.
245	    num_beats_negotiated_but_not_sent_int := (
246	      num_beats_negotiated_but_not_sent
247	      - to_integer(ar_term)
248	      - to_int(data_transaction_p1)
249	    );
250	
251	    num_empty_words_in_fifo := data_fifo_depth - data_fifo_level;
252	    minus_num_empty_words_in_fifo_that_have_not_been_negotiated <=
253	      num_beats_negotiated_but_not_sent_int - num_empty_words_in_fifo;
254	
255	    num_beats_negotiated_but_not_sent <= num_beats_negotiated_but_not_sent_int;
256	
257	    data_transaction_p1 <= data_transaction;
258	  end process;
259	
260	  address_transaction <= throttled_s2m.ar.ready and throttled_m2s.ar.valid;
261	  data_transaction <= throttled_m2s.r.ready and throttled_s2m.r.valid;
262	
263	end architecture;
264

